T[colorBlu:WrapTextInColorCode("Angleur: ") .. colorYello:WrapTextInColorCode("Modifier Keys ") .. "won't be recognized when the game is in the " .. colorGrae:WrapTextInColorCode("background. ") .. "If you are using the scroll wheel for that purpose. Just bind the wheel alone instead, without modifiers."] = colorBlu:WrapTextInColorCode("Angleur：") .. colorYello:WrapTextInColorCode("修饰键") .. "在游戏处于" .. colorGrae:WrapTextInColorCode("后台") .. "时不会被识别。若使用滚轮，请直接绑定滚轮本身，无需修饰键。"
T["Modifier key "] = "修饰键 "
T["down,\nawaiting additional key press."] = "已按下，\n等待下一按键。"
T[", with modifier "] = "，修饰键 "
T["OneKey removed"] = "一键模式已移除"
T["Can't create Equipment Set without any equippable slotted items. Slot a usable and equippable item to your Extra Items slots first."] = "没有可装备的已放入物品，无法创建装备方案。请先将可装备物品放入“额外物品”槽。"
T["This is a limitation of Classic(not the case for Cata and Retail), since it lacks a proper built-in Equipment Manager, allowing you to slot passive items to your Angleur Set."] = "这是经典旧世的限制（《大地的裂变》与正式服不受影响），因为缺少内置装备管理器，无法将被动物品加入 Angleur 套装。"
T["Created equipment set for " .. colorBlu:WrapTextInColorCode("Angleur" ) .. ". ID is : "] = "已为 " .. colorBlu:WrapTextInColorCode("Angleur") .. " 创建装备方案。ID："
T["All unslotted items in the set have been set to <ignore slot>."] = "该套装中未放入的槽位已设为 <忽略槽位>。"
T["For passive items you'd like to add to your fishing gear, you can use the game's " .. colorYello:WrapTextInColorCode("Equipment Manager ") .. "to add them to the " .. colorBlu:WrapTextInColorCode("Angleur ") .. "set"] = "若要将被动物品加入钓鱼装备，可使用游戏内" .. colorYello:WrapTextInColorCode("装备管理器") .. "将其添加到 " .. colorBlu:WrapTextInColorCode("Angleur") .. " 套装。"
T["Couldn't equip slotted item in time before combat"] = "战斗开始前未能及时装备已放入的物品"
T["Slotted items successfully updated for your " .. colorYello:WrapTextInColorCode("Angleur Equipment Set.")] = "已成功更新" .. colorYello:WrapTextInColorCode("Angleur 装备方案") .. "中的已放入物品。"
T["   The " .. colorYello:WrapTextInColorCode("Update/Create Set ") .. "Button automatically adds equippable items in your " .. colorYello:WrapTextInColorCode("Extra Items ") .. "slots to your " .. colorBlu:WrapTextInColorCode("Angleur Set") .. ", and creates one if there isn't already.\n\nIf you want to " .. colorRed:WrapTextInColorCode("remove ") .. "previously saved slotted items, you need to click the " .. colorRed:WrapTextInColorCode("Delete ") .. "Button to the top right, and then re-create the set - or manually change the item set.\n\nYou may also assign " .. colorGrae:WrapTextInColorCode("- Passive Items - ") .. "to your ".. colorBlu:WrapTextInColorCode("Angleur Set ") .. "manually, and Angleur will swap them in and out like the rest."] = "   " .. colorYello:WrapTextInColorCode("更新/创建套装") .. "按钮会自动将" .. colorYello:WrapTextInColorCode("扩展物品") .. "槽中的可装备物品加入" .. colorBlu:WrapTextInColorCode("Angleur 套装") .. "，若不存在则会创建。\n\n若要" .. colorRed:WrapTextInColorCode("移除") .. "已保存的物品，请点击右上角的" .. colorRed:WrapTextInColorCode("删除") .. "按钮后重新创建，或手动修改装备方案。\n\n你也可以手动将" .. colorGrae:WrapTextInColorCode("被动物品") .. "加入" .. colorBlu:WrapTextInColorCode("Angleur 套装") .. "，Angleur 也会自动切换它们。"
T["ITEM NOT FOUND IN BAGS. TO USE FOR EQUIPMENT SWAP, EITHER ADD IT MANUALLY TO ANGLEUR SET OR RE-DRAG THE MACRO."] = "背包中未找到该物品。若要用于装备切换，请手动加入 Angleur 套装或重新拖拽宏。"
T["Equipping of the Angleur set disrupted due to sudden combat"] = "因突发战斗，Angleur 套装装备被中断"
T["Unslotted " .. colorBlu:WrapTextInColorCode("Angleur ") .. colorYello:WrapTextInColorCode("Equipment Set ") .. " item. Remove it from the Angleur set in the equipment manager if you don't want Angleur to keep equipping it."] = "已移出 " .. colorBlu:WrapTextInColorCode("Angleur ") .. colorYello:WrapTextInColorCode("装备方案") .. " 的物品。若不希望 Angleur 继续装备它，请在装备管理器中将其移除。"
T[colorBlu:WrapTextInColorCode("Angleur: ") .. colorYello:WrapTextInColorCode("Fishing Hat") .. " detected."] = colorBlu:WrapTextInColorCode("Angleur：") .. colorYello:WrapTextInColorCode("检测到钓鱼帽") .. "。"
T["For it to work properly, please make sure to add it as a macro like so: "] = "为确保正常工作，请按如下方式将其添加为宏："
T["Otherwise, you will have to manually target your fishing rod every time." .. "If you want to see an example of how to slot macros, click the " ..  colorRed:WrapTextInColorCode("[HOW?] ") .. "button on the " .. colorYello:WrapTextInColorCode("Extra Tab")] = "否则每次都需要手动选中鱼竿。" .. "若要查看宏放入示例，请点击" .. colorRed:WrapTextInColorCode("[如何操作？]") .. "按钮（位于" .. colorYello:WrapTextInColorCode("扩展") .. "标签页）。"
T["Can't drag item in combat."] = "战斗中无法拖动物品。"
T["Please select a usable item."] = "请选择可使用的物品。"
T["This item does not have a castable spell."] = "该物品没有可施放的法术。"
T["Can't drag macro in combat."] = "战斗中无法拖动宏。"
T["link of macro spell: "] = "宏法术链接："
T["link of macro item: "] = "宏物品链接："
T[colorYello:WrapTextInColorCode("Can't use Macro: ") .. "The item used in this macro doesn't have a trackable spell/aura."] = colorYello:WrapTextInColorCode("无法使用宏：") .. "该宏中使用的物品没有可追踪的法术/光环。"
T[colorBlu:WrapTextInColorCode("Angleur: ") .. "Failed to get macro spell/item. If you are using " .. colorYello:WrapTextInColorCode("macro conditions \n") .. "you need to drag the macro into the button frame when the conditions are met."] = colorBlu:WrapTextInColorCode("Angleur：") .. "获取宏的法术/物品失败。若使用" .. colorYello:WrapTextInColorCode("宏条件") .. "，请在条件满足时拖入宏。"
T["Failed to get macro index"] = "获取宏索引失败"
T["Macro empty"] = "宏为空"
T[colorBlu:WrapTextInColorCode("Angleur: ") .. "Macro successfully slotted. If you make changes to it, you need to " .. colorYello:WrapTextInColorCode("re-drag ") .. "the new version to the slot. You can also delete the macro to save space, Angleur will remember it."] = colorBlu:WrapTextInColorCode("Angleur：") .. "宏已成功放入。若修改宏，请" .. colorYello:WrapTextInColorCode("重新拖拽") .. "新版本到槽位。也可删除宏以节省空间，Angleur 会记住它。"
T["Timer set to: "] = "计时器设置为："
T[" minutes, "] = " 分钟，"
T[" seconds"] = " 秒"
